css:
/* === 使用了墨千尾老师的模板 | 模板链接：https://discord.com/channels/1291925535324110879/1422717884378910801 | 非常感谢 === */

/* === 顶栏背景 === */
#top-settings-holder {
  background-image: url('https://image.uglycat.cc/wxo2sh.jpeg') !important;
  background-size: 100% 100% !important;
  background-position: center !important;
  background-repeat: no-repeat !important;
  background-color: transparent !important;
  border: none !important;
  box-shadow: none !important;
  border-radius: 0 !important;
}

/* === 顶栏容器圆角同步（可选） === */
#top-bar {
  border-radius: 0 !important;
  background-color: transparent !important;
  box-shadow: none !important;
  border: none !important;
}
/* ----------------------------- */
/* 顶栏图标替换：极限兼容版 */
/* ----------------------------- */

/* 先彻底隐藏字体伪元素和 svg（防止遮挡） */
#top-settings-holder .drawer-icon::before,
#top-settings-holder .drawer-icon::after {
  display: none !important;
  content: none !important;
}
#top-settings-holder .drawer-icon svg,
#top-settings-holder .drawer-icon img {
  display: none !important;
}

/* 基础样式：保证图标容器能显示背景图 */
#top-settings-holder .drawer-icon,
#top-settings-holder .drawer .drawer-icon,
#top-settings-holder [class*="drawer-icon"] {
  display: inline-block !important;
  width: 34px !important;
  height: 34px !important;
  min-width: 34px !important;
  min-height: 34px !important;
  line-height: 34px !important;
  background-position: center center !important;
  background-repeat: no-repeat !important;
  background-size: contain !important;
  overflow: visible !important;
  vertical-align: middle !important;
  -webkit-mask-image: none !important; /* 防止被 mask 掉 */
  mask-image: none !important;
}

/* ========== 通用九个图标（默认） ========== */
/* 针对各种 class 前缀/变体都列出，避免类名不一致的情况 */
#top-settings-holder .drawer-icon:nth-child(1),
#top-settings-holder .drawer-icon:nth-child(2),
#top-settings-holder .drawer-icon:nth-child(3),
#top-settings-holder .drawer-icon:nth-child(4),
#top-settings-holder .drawer-icon:nth-child(6),
#top-settings-holder .drawer-icon:nth-child(7),
#top-settings-holder .drawer-icon:nth-child(8),
#top-settings-holder .drawer-icon:nth-child(9),
#top-settings-holder .drawer-icon:nth-child(10),

/* 以及按类名匹配的备用写法 */
#top-settings-holder .drawer-icon[class*="fa-sliders"],
#top-settings-holder .drawer-icon[class*="fa-plug"],
#top-settings-holder .drawer-icon[class*="fa-font"],
#top-settings-holder .drawer-icon[class*="fa-book"],
#top-settings-holder .drawer-icon[class*="fa-image"],
#top-settings-holder .drawer-icon[class*="fa-cubes"],
#top-settings-holder .drawer-icon[class*="fa-bars"],
#top-settings-holder .drawer-icon[class*="fa-face"],
#top-settings-holder .drawer-icon[class*="fa-address"] {
  background-image: url("https://image.uglycat.cc/z4ye9m.png") !important;
  background-size: contain !important;
  background-position: center !important;
  width: 34px !important;
  height: 34px !important;
  opacity: 1 !important;
}

/* ========== 第5个图标 单独覆盖（类名匹配 + nth-child） ========== */
/* nth-child 保险+按类名保险双写，提高命中率 */
#top-settings-holder .drawer-icon:nth-child(5),
#top-settings-holder .drawer .drawer-icon:nth-child(5),

#top-settings-holder .drawer-icon[class*="fa-user"],
#top-settings-holder .drawer-icon[class*="fa-regular fa-user"],
#top-settings-holder .drawer-icon[class*="fa-solid fa-user"],
#top-settings-holder .drawer-icon[class*="fa-user-"] {
  background-image: url("https://image.uglycat.cc/j070vs.png") !important;
  background-size: contain !important;
  background-position: center !important;
  width: 40px !important;
  height: 40px !important;
  z-index: 999 !important;
  opacity: 1 !important;
}

/* 同时覆盖 open/closed 状态的类名（避免展开态被覆盖） */
#top-settings-holder .drawer-icon.openIcon,
#top-settings-holder .drawer-icon.closedIcon,
#top-settings-holder .drawer-icon.openIcon[class*="fa-user"],
#top-settings-holder .drawer-icon.closedIcon[class*="fa-user"] {
  background-size: contain !important;
  background-position: center !important;
  background-repeat: no-repeat !important;
}

/* 若图标由子 <i> 渲染（部分实现会把图标放在 <i> 内），把背景强制放到父元素并隐藏内部 <i> */
#top-settings-holder .drawer-icon > i,
#top-settings-holder .drawer-icon i {
  display: none !important;
  width: 0 !important;
  height: 0 !important;
  line-height: 0 !important;
}

/* 额外保险：如果是按钮包裹图标也适配 */
#top-settings-holder button .drawer-icon,
#top-settings-holder a .drawer-icon {
  background-size: contain !important;
  background-position: center !important;
}

/* 最后再一次确保没有伪元素干扰 */
#top-settings-holder .drawer-icon::before { display: none !important; content:none !important; }

/* === 底栏背景 === */
#send_form {
  background-image: url('https://image.uglycat.cc/u9syo1.png') !important;
  background-repeat: repeat-x !important;
  background-size: auto 100% !important;
  background-position: center bottom !important;
  border: none !important;
  border-radius: 0 !important;
  padding: 8px !important;
}

/* === 聊天背景图 === */
#chat {
  background-image: url('https://image.uglycat.cc/zalkhz.png') !important;
  background-size: cover !important;
  background-position: center !important;
  background-repeat: no-repeat !important;
  background-attachment: fixed !important;
  background-color: transparent !important;
}

/* === 输入框透明 + 清理多余边线 === */
#send_textarea {
  background-color: transparent !important;
  border: none !important;
  color: #fff !important;
}


/* 1. 全局弹窗面板背景图统一替换（覆盖所有顶栏图标打开的弹窗） */
/* 基础抽屉弹窗（AI配置、API连接、格式化等核心面板） */
.drawer-content,
/* 表格类弹窗（如记忆表格，文档提及类名） */
#table_drawer_content,
/* 选项类弹窗（子选项弹窗） */
.options-content {
    background-image: url('https://image.uglycat.cc/zalkhz.png') !important;
    background-size: cover !important; /* 背景图覆盖整个面板，适配不同尺寸 */
    background-position: center !important; /* 背景图居中显示 */
    background-repeat: no-repeat !important; /* 背景图不重复平铺 */
    background-color: transparent !important; /* 透明底色，避免遮挡背景图 */
    /* 保留文档中推荐的边框与圆角兼容性设置 */
    border-color: rgba(255,255,255,0.2) !important;
    border-radius: 8px !important; /* 可选：添加圆角让面板更美观，数值可自调 */
}

/* 2. 特殊位置弹窗补充适配（左侧/右侧弹出面板） */
/* 左侧弹窗（如AI响应配置面板） */
.drawer-content.fillLeft,
/* 右侧弹窗（如角色管理面板） */
.drawer-content.fillRight {
    background-image: url('https://image.uglycat.cc/zalkhz.png') !important;
    background-attachment: fixed !important; /* 固定背景，避免滚动时偏移 */
}

/* 3. 关闭状态弹窗初始化（确保打开时背景图立即显示） */
.drawer-content.closedDrawer {
    background-image: url('https://image.uglycat.cc/zalkhz.png') !important;
    background-opacity: 1 !important; /* 避免关闭状态下背景图透明 */
}

/* 4. 弹窗内部容器适配（防止内容遮挡背景图，参考文档“聊天气泡背景”写法） */
/* AI配置面板内部容器 */
#left-nav-panel,
/* 世界信息面板内部容器 */
#WorldInfo,
/* 用户设置面板内部容器 */
#user-settings-block,
/* 角色管理面板内部容器 */
#right-nav-panel {
    background-color: transparent !important; /* 内部容器透明，透出底层背景图 */
    backdrop-filter: blur(4px) !important; /* 可选：添加轻微模糊，让文字更易读（文档推荐效果） */
}
/* -- ②.不同图片（链接） -- */
/* 基础设置 */
#send_form [class*="fa-"]::before {
  content: '' !important;
  display: inline-block;
  width: 35px; /* 图片宽度 */
  height: 35px; /* 图片高度 */
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  vertical-align: middle;
}

/* 菜单 */
#options_button::before {
  background-image: url('https://image.uglycat.cc/o497tc.png') !important;
}

/* 扩展 */
#extensionsMenuButton::before {
  background-image: url('https://image.uglycat.cc/2mt77h.png') !important;
}

/* QR */
#quick-reply-rocket-button i::before {
  background-image: url('https://image.uglycat.cc/2mt77h.png') !important;
}

/* 发送 */
#send_but::before {
  background-image: url('https://image.uglycat.cc/hb7hx1.png') !important;
}

/* 停止 */
#mes_stop i::before {
  background-image: url('https://image.uglycat.cc/jlojfu.png') !important;
}

/* 1. 目标布局：头像在上+三元素在头像下横向居中（保留气泡透明，移除描边） */
/* be like：
*          头像
*      楼层 计时 词符
* ------------------------
*          文本
* 二改自Nakari的代码
*/
.mes {
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important; 
    gap: 8px; /* 气泡内元素间距，可按需调整 */
    background: transparent !important; /* 气泡完全透明 */
    border: none !important; /* 移除灰色描边 */
    border-radius: 8px; /* 可选：气泡圆角，数值按需调整 */
}

.mes .mes_block {
    background: transparent !important;
    border: none !important; /* 清除文本区域多余边框 */
    position: relative; /* 作为分割线文字的定位基准 */
    /* 给文本区域底部留空，避免文字被遮挡 */
    padding-bottom: 25px !important;
}

/* 文字作为分割线：✟⁺₊𝕱𝖔𝖗𝖇𝖎𝖉𝖉𝖊𝖓 𝖑𝖔𝖛𝖊 𝖎𝖘 𝖒𝖞 𝖈𝖗𝖚𝖈𝖎𝖋𝖎𝖝₊⁺✟（确保显示+分割线效果） */
.mes .mes_block::after {
    content: '✟⁺₊𝕱𝖔𝖗𝖇𝖎𝖉𝖉𝖊𝖓 𝖑𝖔𝖛𝖊 𝖎𝖘 𝖒𝖞 𝖈𝖗𝖚𝖈𝖎𝖋𝖎𝖝₊⁺✟';
    position: absolute;
    bottom: 0 !important; /* 固定在文本区域最底部，作为分割线 */
    left: 50%;
    transform: translateX(-50%) !important; /* 强制水平居中 */
    font-size: 14px !important; /* 增大字号，凸显分割线效果 */
    color: #999999 !important; /* 明确颜色，避免透明 */
    white-space: nowrap !important; /* 防止文字换行，保持完整分割线 */
    pointer-events: none; /* 避免遮挡交互 */
    z-index: 5 !important; /* 提高层级，防止被其他元素覆盖 */
    /* 可选：添加上下短线，强化分割线视觉 */
    padding: 5px 0;
    border-top: 1px solid #999999;
    border-bottom: 1px solid #999999;
    width: 100% !important; /* 让分割线宽度匹配气泡 */
    text-align: center !important; /* 确保文字在分割线内居中 */
}

/* 2. 头像与三元素布局细节 */
.mes .mesAvatarWrapper {
    display: flex;
    align-items: center;
    flex-wrap: wrap;     /* 允许三元素换行到头像下方 */
    justify-content: center; /* 三元素横向居中 */
    gap: 8px; /* 三元素之间的间距，可按需调整 */
}

.mesAvatarWrapper .avatar {
    flex-basis: 100%;       /* 头像独占一行，三元素挤到下方 */
    margin-bottom: 15px;   /* 头像与下方三元素的间距，可按需调整 */
    display: flex;          /* 头像内部图片居中 */
    justify-content: center;
    position: relative; /* 作为图片素材定位基准 */
    pointer-events: none !important; /* 禁用头像容器误触 */
    background-color: transparent !important; /* 确保无多余色块 */
    border: none !important;
    border-radius: 0 !important; /* 清除容器圆角，避免影响图片圆形效果 */
    width: 50px !important; /* 固定头像容器宽度，与图片一致 */
    height: 50px !important; /* 固定头像容器高度，与图片一致 */
}

/*  如果使用上边这个排版方式，头像附近会产生看不见但会被点击到的avatar容器，容易误把头像图片点开，请搭配NA的以下代码使用↓ */
/* 恢复头像图片的点击效果 + 固定圆形头像 */
.mes .avatar img {
    position: relative;
    z-index: 10 !important; /* 头像图片层级高于素材 */
    pointer-events: auto !important; /* 恢复头像图片点击 */
    width: 50px !important; /* 固定头像宽度 */
    height: 50px !important; /* 固定头像高度，与宽度一致确保圆形 */
    object-fit: cover; /* 头像填满容器，避免拉伸变形 */
    border-radius: 50% !important; /* 关键：设置圆形头像，覆盖原生样式 */
}

/* 4. 图片素材完全被头像覆盖（隐藏）- 统一用户与AI位置 */
.mes .avatar::after {
    content: '';
    position: absolute;
    bottom: -30px !important; /* 素材顶部与头像底部对齐，统一垂直位置 */
    left: 48% !important; /* 水平居中对齐头像 */
    transform: translateX(-50%) !important; /* 抵消left:50%的偏移，确保完全居中 */
    width: 100px !important; /* 素材尺寸与头像一致，避免超出 */
    height: 100px !important;
    background-image: url('https://image.uglycat.cc/re6nfh.png'); /* 你的素材链接 */
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    pointer-events: none;
    z-index: 1 !important; /* 素材层级最低，被圆形头像覆盖 */
}
/* === 结束 === */
